import React, { useEffect, useMemo, useState } from 'react';
import { io } from 'socket.io-client';
import { useNavigate } from 'react-router-dom';
import { LogOut, GraduationCap, Star, ShieldCheck, PlayCircle, BookOpen, Bell } from 'lucide-react';
import Library from '../components/Library';



const StudentDashboard = () => {
  const navigate = useNavigate();
  let user = null;
  if (typeof window !== 'undefined') {
    const stored = localStorage.getItem('ethioBooksUser');
    if (stored) {
      try {
        user = JSON.parse(stored);
      } catch {
        user = null;
      }
    }
  }

  const studentGrade = Number(user?.grade) || 7;
  const isPremium = !!user?.isPremium;

  const [selectedGrade, setSelectedGrade] = useState(studentGrade);
  const [activeVideoUrl, setActiveVideoUrl] = useState('');
  const [toast, setToast] = useState(null);

  // Filtered Content
  const textbooks = useMemo(() => [
    { id: 1, title: 'Grade 7 Mathematics Textbook', grade: 7, fileUrl: '#' },
    { id: 2, title: 'Grade 10 Physics Essentials', grade: 10, fileUrl: '#' },
    { id: 3, title: 'Grade 12 Biology Revision Notes', grade: 12, fileUrl: '#' }
  ].filter((item) => item.grade === Number(selectedGrade)), [selectedGrade]);

  const videoTutors = useMemo(() => [
    { id: 1, title: 'Algebra Basics – Trial Class', grade: 7, videoUrl: 'https://www.youtube.com/embed/dQw4w9WgXcQ' },
    { id: 2, title: 'Grade 10 Chemistry Concepts', grade: 10, videoUrl: 'https://www.youtube.com/embed/dQw4w9WgXcQ' }
  ].filter((item) => item.grade === Number(selectedGrade)), [selectedGrade]);

  const tutors = useMemo(() => [
    { id: 1, name: 'Abebe Bekele', rating: 4.8, about: 'Passionate math tutor with 5+ years helping high school students excel.', achievements: 'National Math Olympiad finalist.', trialVideoUrl: 'https://www.youtube.com/embed/dQw4w9XcQ' },
    { id: 2, name: 'Sara Mekonnen', rating: 4.9, about: 'Physics and chemistry tutor focused on conceptual understanding.', achievements: 'Top 1% national exam scorer.', trialVideoUrl: 'https://www.youtube.com/embed/dQw4w9XcQ' }
  ], []);

  useEffect(() => {
    const token = localStorage.getItem('ethioBooksToken');
    if (!token) return;
    const socket = io('http://localhost:5000', { auth: { token } });
    socket.on('notification', (payload) => {
      setToast(payload);
      setTimeout(() => setToast(null), 5000);
    });
    return () => socket.disconnect();
  }, []);

  const handleLogout = () => {
    localStorage.clear();
    navigate('/');
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC]">
      {/* Header - Full Width constrained to 1440px */}
      <header className="sticky top-0 z-30 w-full bg-white/80 backdrop-blur-md border-b border-gray-100">
        <div className="max-w-[1440px] mx-auto px-6 lg:px-12 py-4 flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <div className="bg-blue-600 p-2 rounded-lg">
              <BookOpen className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Ethio Books</h1>
              <p className="text-xs text-gray-500 font-medium">Welcome, {user?.fullName || 'Student'} • Grade {studentGrade}</p>
            </div>
          </div>

          <div className="flex items-center space-x-6">
            <div className="hidden md:flex items-center space-x-2 bg-gray-50 px-3 py-1.5 rounded-full border border-gray-100">
              <GraduationCap className="w-4 h-4 text-blue-600" />
              <select 
                className="bg-transparent text-xs font-semibold focus:outline-none cursor-pointer"
                value={selectedGrade}
                onChange={(e) => setSelectedGrade(e.target.value)}
              >
                {[7, 8, 9, 10, 11, 12].map(g => <option key={g} value={g}>Grade {g}</option>)}
              </select>
            </div>
            <button onClick={handleLogout} className="p-2 text-gray-400 hover:text-red-500 transition-colors">
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-[1440px] mx-auto px-6 lg:px-12 py-10 space-y-12">
        {/* Real-time Toast */}
        {toast && (
          <div className="fixed bottom-8 right-8 z-50 flex items-start space-x-4 bg-white border border-blue-100 shadow-2xl rounded-2xl p-4 animate-in slide-in-from-right-10">
            <div className="bg-blue-100 p-2 rounded-lg"><Bell className="w-5 h-5 text-blue-600" /></div>
            <div>
              <p className="font-bold text-gray-900 text-sm">Update</p>
              <p className="text-gray-600 text-xs">{toast.message}</p>
            </div>
          </div>
        )}

        {/* Premium Banner - Enhanced with Gradient */}
        {!isPremium && (
          <div className="relative overflow-hidden rounded-3xl bg-gradient-to-r from-blue-600 to-indigo-700 p-8 text-white shadow-xl shadow-blue-200/50 group">
            <div className="relative z-10 flex flex-col lg:flex-row lg:items-center justify-between gap-6">
              <div className="space-y-2">
                <h2 className="text-2xl font-bold flex items-center gap-2">
                  <ShieldCheck className="w-7 h-7 text-blue-200" />
                  Elevate Your Learning Experience
                </h2>
                <p className="text-blue-100 max-w-2xl text-sm leading-relaxed">
                  Join our Premium community to unlock exclusive textbooks, personalized quizzes, and direct 1-on-1 messaging with Ethiopia's top-rated tutors.
                </p>
              </div>
              <button className="bg-white text-blue-700 px-8 py-4 rounded-2xl font-bold text-sm hover:bg-blue-50 transition-all hover:scale-105 active:scale-95 shadow-lg">
                Upgrade to Premium
              </button>
            </div>
            {/* Background Decorative Circles */}
            <div className="absolute top-[-20%] right-[-5%] w-64 h-64 bg-white/10 rounded-full blur-3xl" />
          </div>
        )}

        {/* Bento Grid: Textbooks & Videos */}
        <section className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-white rounded-3xl p-8 border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-lg font-bold text-gray-900">Textbooks Base</h3>
              <span className="bg-blue-50 text-blue-700 text-[10px] font-bold px-3 py-1 rounded-full uppercase tracking-wider">Grade {selectedGrade}</span>
            </div>
            <div className="space-y-4">
              {textbooks.map(book => (
                <div key={book.id} className="flex items-center justify-between p-4 rounded-2xl border border-gray-50 bg-gray-50/30 hover:bg-white hover:border-blue-100 hover:shadow-sm transition-all group">
                  <div className="flex items-center space-x-4">
                    <div className="bg-white p-2 rounded-xl border border-gray-100 group-hover:text-blue-600"><BookOpen className="w-5 h-5" /></div>
                    <span className="font-semibold text-gray-700 text-sm">{book.title}</span>
                  </div>
                  <button className="text-xs font-bold text-blue-600 hover:underline">Open PDF</button>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-white rounded-3xl p-8 border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-lg font-bold text-gray-900">Video Tutors</h3>
              <PlayCircle className="w-5 h-5 text-gray-400" />
            </div>
            <div className="space-y-4">
              {videoTutors.map(video => (
                <div key={video.id} onClick={() => setActiveVideoUrl(video.videoUrl)} className="cursor-pointer flex items-center justify-between p-4 rounded-2xl bg-gray-900 text-white hover:bg-gray-800 transition-all shadow-lg shadow-gray-200">
                  <span className="font-medium text-sm">{video.title}</span>
                  <div className="bg-white/20 p-1.5 rounded-full"><PlayCircle className="w-4 h-4 text-white" /></div>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* Global Library Component */}
        <Library />

        {/* Tutor Marketplace - Full Responsive Grid */}
        <section className="space-y-8">
          <div className="flex items-end justify-between">
            <div className="space-y-1">
              <h2 className="text-2xl font-bold text-gray-900">Tutor Marketplace</h2>
              <p className="text-gray-500 text-sm">Learn from the best educators in the country.</p>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
            {tutors.map((tutor) => (
              <div key={tutor.id} className="group bg-white rounded-3xl border border-gray-100 p-6 hover:border-blue-200 hover:shadow-2xl hover:shadow-blue-100/50 transition-all duration-300 flex flex-col">
                <div className="flex justify-between items-start mb-4">
                  <div className="w-12 h-12 bg-blue-100 rounded-2xl flex items-center justify-center text-blue-600 font-bold text-xl">
                    {tutor.name[0]}
                  </div>
                  <div className="flex items-center space-x-1 bg-yellow-50 px-2 py-1 rounded-lg">
                    <Star className="w-3 h-3 text-yellow-500 fill-yellow-500" />
                    <span className="text-[10px] font-bold text-yellow-700">{tutor.rating}</span>
                  </div>
                </div>
                <h3 className="font-bold text-gray-900 group-hover:text-blue-600 transition-colors">{tutor.name}</h3>
                <p className="text-xs text-gray-500 mt-2 line-clamp-2 leading-relaxed">{tutor.about}</p>

                <div className="mt-6 pt-6 border-t border-gray-50 flex gap-3">
                  <button 
                    onClick={() => setActiveVideoUrl(tutor.trialVideoUrl)}
                    className="flex-1 text-[11px] font-bold py-2.5 rounded-xl bg-gray-50 text-gray-700 hover:bg-gray-100 transition-colors"
                  >
                    Trial Video
                  </button>
                  <button className="flex-1 text-[11px] font-bold py-2.5 rounded-xl bg-blue-600 text-white hover:bg-blue-700 shadow-md transition-all">
                    Buy Content
                  </button>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Modal Overlay */}
        {activeVideoUrl && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-gray-900/90 backdrop-blur-sm" onClick={() => setActiveVideoUrl('')} />
            <div className="relative w-full max-w-4xl aspect-video bg-black rounded-3xl overflow-hidden shadow-2xl border border-white/10">
               <iframe src={activeVideoUrl} title="Video" className="w-full h-full" frameBorder="0" allowFullScreen />
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default StudentDashboard;
